			expect(screen.getByText("12")).toBeTruthy()
		})
	})

	describe("description and division scaling", () => {
		it("shows description text", () => {
			render(
				<CompetitionWorkoutCard
					{...defaultProps}
					description="21-15-9 Thrusters and Pull-ups"
				/>,
